let stats = global.get("vehiculo_stats") || {
    todayCount: 0,
    totalCount: 0,
    gateState: "CERRADA",
    lightState: "ROJO",
    lastDistance: 150,
    hourlyTraffic: Array(12).fill(0),
    logs: []
};

let msgString = msg.payload.toString();

// Formato de hora local para los logs
let now = new Date();
let timeStr = now.toLocaleDateString() + " " + now.toLocaleTimeString();

// Detectar distancia y número de auto: "ALERTA: Carro #1 detectado a 12 cm"
let matchCar = msgString.match(/Carro\s+#(\d+)\s+detectado\s+a\s+(\d+)\s+cm/);

if (matchCar) {
    let dist = parseInt(matchCar[2]);
    stats.lastDistance = dist;

    // Incrementar contadores
    stats.todayCount += 1;
    stats.totalCount += 1;

    // Sumar 1 a la hora actual en el gráfico (último elemento de la lista de 12 horas)
    stats.hourlyTraffic[11] += 1;

    stats.logs.push({
        time: timeStr,
        event: "Vehículo Detectado (Físico)",
        distance: dist + " cm",
        state: stats.gateState
    });
} else if (msgString.includes("VERDE") || msgString.includes("Subiendo barrera")) {
    stats.gateState = "ABIERTA";
    stats.lightState = "VERDE";
    stats.logs.push({
        time: timeStr,
        event: msgString,
        distance: stats.lastDistance + " cm",
        state: "ABIERTA"
    });
} else if (msgString.includes("AMARILLO")) {
    stats.gateState = "CERRANDO";
    stats.lightState = "AMARILLO";
    stats.logs.push({
        time: timeStr,
        event: msgString,
        distance: stats.lastDistance + " cm",
        state: "CERRANDO"
    });
} else if (msgString.includes("ROJO") || msgString.includes("Bajando barrera")) {
    stats.gateState = "CERRADA";
    stats.lightState = "ROJO";
    stats.logs.push({
        time: timeStr,
        event: msgString,
        distance: stats.lastDistance + " cm",
        state: "CERRADA"
    });
} else {
    // Log genérico para otras publicaciones de estado
    stats.logs.push({
        time: timeStr,
        event: msgString,
        distance: stats.lastDistance + " cm",
        state: stats.gateState
    });
}

// Mantener últimos 50 logs para no sobrecargar memoria
if (stats.logs.length > 50) {
    stats.logs.shift();
}

global.set("vehiculo_stats", stats);
return null;

