let comando = msg.payload.comando; // "ABRIR", "CERRAR" o "AUTO"

let stats = global.get("vehiculo_stats") || {
    todayCount: 0,
    totalCount: 0,
    gateState: "CERRADA",
    lightState: "ROJO",
    lastDistance: 150,
    hourlyTraffic: Array(12).fill(0),
    logs: []
};

let now = new Date();
let timeStr = now.toLocaleDateString() + " " + now.toLocaleTimeString();

if (comando === "ABRIR") {
    stats.gateState = "ABIERTA";
    stats.lightState = "VERDE";
    stats.logs.push({
        time: timeStr,
        event: "Comando: Abrir Barrera (Manual)",
        distance: "--",
        state: "ABIERTA"
    });
} else if (comando === "CERRAR") {
    stats.gateState = "CERRADA";
    stats.lightState = "ROJO";
    stats.logs.push({
        time: timeStr,
        event: "Comando: Cerrar Barrera (Manual)",
        distance: "--",
        state: "CERRADA"
    });
} else if (comando === "AUTO") {
    stats.logs.push({
        time: timeStr,
        event: "Restableciendo Control Automático",
        distance: "--",
        state: stats.gateState
    });
}

global.set("vehiculo_stats", stats);

// Mandamos la respuesta HTTP rápida al dashboard
let responseMsg = {
    payload: { status: "success", comando: comando },
    statusCode: 200,
    headers: {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Headers": "Content-Type",
        "Access-Control-Allow-Methods": "GET, POST, OPTIONS"
    }
};

// Duplicamos el mensaje: uno para HTTP Response, otro para el broker MQTT
let mqttMsg = {
    payload: comando
};

return [responseMsg, mqttMsg];

let initialStats = {
    todayCount: 0,
    totalCount: 0,
    gateState: "CERRADA",
    lightState: "ROJO",
    lastDistance: 150,
    hourlyTraffic: Array(12).fill(0),
    logs: []
};

global.set("vehiculo_stats", initialStats);

msg.payload = { status: "success", message: "Datos reiniciados a cero" };
return msg;
